function updateTVL(uint256 chainId, uint256 tvl, uint256 updateTime) external nonReentrant {
    if (msg.sender != lzHelper) revert IConnector_InvalidSender();

    registry.updateHoldingPostionWithTime(
        vaultId,
        registry.calculatePositionId(address(this), OMNICHAIN_POSITION_ID, abi.encode(chainId)),
        "",
        abi.encode(tvl),
        tvl <= DUST_LEVEL,
        updateTime
    );
}

function updateHoldingPostionWithTime(
    uint256 vaultId,
    bytes32 _positionId,
    bytes calldata _data,
    bytes calldata additionalData,
    bool removePosition,
    uint256 positionTimestamp
) external vaultExists(vaultId) {
    uint256 positionIndex = updateHoldingPosition(vaultId, _positionId, _data, additionalData, removePosition);
    if (positionIndex != type(uint256).max) {
        vaults[vaultId].holdingPositions[positionIndex].positionTimestamp = positionTimestamp;
    }
}
